import React, { useEffect, useState } from 'react';
import { ViewTitle } from 'components/ViewTitle';
import * as actions from '../../redux/actions';
import { useDispatch, useSelector } from 'react-redux';
import { useHistory } from 'react-router-dom';
import dayjs from 'dayjs';
import FilterTimestampReportCard from '../../components/Card/FilterTimestampReportCard';
import _ from 'lodash';
import { timestampReportPersonal, timeStampMontlyReport } from 'components/PDF';
import Monthlyreport from '../../components/Card/Monthlyreport';
import weekday from 'dayjs/plugin/weekday';
import localeData from 'dayjs/plugin/localeData';

// Material-UI
import {
  Box,
  Card,
  Container,
  Typography,
  Paper,
  Button,
  Chip,
  Divider,
  Grid,
  ToggleButtonGroup,
  ToggleButton,
  Fade,
  alpha,
  useTheme,
  Stack,
  IconButton,
  Tooltip,
  TextField,
  MenuItem,
  InputAdornment,
  Collapse,
  Badge,
  Tab,
  Tabs,
  Menu,
  Select,
  FormControl,
  InputLabel,
} from '@mui/material';

// Icons
import CalendarMonthIcon from '@mui/icons-material/CalendarMonth';
import PrintIcon from '@mui/icons-material/Print';
import DownloadIcon from '@mui/icons-material/Download';
import DateRangeIcon from '@mui/icons-material/DateRange';
import FilterAltIcon from '@mui/icons-material/FilterAlt';
import PersonIcon from '@mui/icons-material/Person';
import WorkIcon from '@mui/icons-material/Work';
import BusinessIcon from '@mui/icons-material/Business';
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight';
import KeyboardArrowLeftIcon from '@mui/icons-material/KeyboardArrowLeft';
import TodayIcon from '@mui/icons-material/Today';
import VisibilityIcon from '@mui/icons-material/Visibility';
import FilterAltOffIcon from '@mui/icons-material/FilterAltOff';
import MoreVertIcon from '@mui/icons-material/MoreVert';

dayjs.extend(weekday);
dayjs.extend(localeData);

export default function HrReport({ title, subtitle }) {
  const theme = useTheme();
  const history = useHistory();
  const dispatch = useDispatch();
  const employees = useSelector((state) => state.employee);
  const timestamp = useSelector((state) => state.timestamp);
  const roletype = useSelector((state) => state.roletype);
  const project = useSelector((state) => state.project);
  const me = useSelector((state) => state.me);

  const [name, setName] = useState('');
  const [page, setPage] = useState(1);
  const [size, setSize] = useState(9999);
  const [emSelect, setEmSelect] = useState();
  const [dateStart, setDateStart] = useState(dayjs());
  const [dateEnd, setDateEnd] = useState(new Date());
  const [month, setMonth] = useState(dayjs().month());
  const [year, setYear] = useState(dayjs().year());
  const [roleSelect, setRoleSelect] = useState();
  const [projectSelect, setProjectSelect] = useState();
  const [selectedOption, setSelectedOption] = useState('Month');
  const [countDay, setCountDay] = useState(
    dayjs(`${year}-${month + 1}`).daysInMonth(),
  );
  const [startDay, setStartDay] = useState(1);
  const [showFilters, setShowFilters] = useState(false);
  const [menuAnchorEl, setMenuAnchorEl] = useState(null);

  const daysInMonth = dayjs(`${year}-${month + 1}`).daysInMonth();
  const midDay = Math.ceil(daysInMonth / 2);
  const days = Array.from({ length: countDay }, (_, i) => i + startDay);
  const monthNames = [
    'มกราคม',
    'กุมภาพันธ์',
    'มีนาคม',
    'เมษายน',
    'พฤษภาคม',
    'มิถุนายน',
    'กรกฎาคม',
    'สิงหาคม',
    'กันยายน',
    'ตุลาคม',
    'พฤศจิกายน',
    'ธันวาคม',
  ];

  useEffect(() => {
    dispatch(
      actions.timestampAll({
        cal: true,
        size,
        page,
        emSelect,
        dateStart: dayjs().month(month).startOf('month').toISOString(),
        dateEnd: dayjs().month(month).endOf('month').toISOString(),
        roleSelect,
        project_id: projectSelect?._id,
      }),
    );
    return () => {};
  }, [emSelect, dateStart, dateEnd, month, year, roleSelect, projectSelect]);

  useEffect(() => {
    dispatch(actions.employeeAll({}));
    dispatch(actions.roletypeAll({}));
    dispatch(actions.projectAll({}));
    return () => {};
  }, []);

  const handlePrint = () => {
    timeStampMontlyReport(timestamp, days, month, year, dateStart);
  };

  const handleValueChange = (event) => {
    const count = event.target.value;
    setSelectedOption(count);
    if (count === 'Month') {
      dispatch(
        actions.timestampAll({
          cal: true,
          size,
          page,
          emSelect,
          dateStart: dayjs()
            .year(year)
            .month(month)
            .startOf('month')
            .toISOString(),
          dateEnd: dayjs().year(year).month(month).endOf('month').toISOString(),
          roleSelect,
          project_id: projectSelect?._id,
        }),
      );
      setCountDay(dayjs(`${year}-${month + 1}`).daysInMonth());
      setStartDay(1);
    } else if (count === '15') {
      dispatch(
        actions.timestampAll({
          cal: true,
          size,
          page,
          emSelect,
          dateStart: dayjs()
            .year(year)
            .month(month)
            .startOf('month')
            .toISOString(),
          dateEnd: dayjs().year(year).month(month).date(midDay).toISOString(),
          roleSelect,
          project_id: projectSelect?._id,
        }),
      );
      setCountDay(15);
      setStartDay(1);
    } else if (count === '31') {
      dispatch(
        actions.timestampAll({
          cal: true,
          size,
          page,
          emSelect,
          dateStart: dayjs().year(year).month(month).date(midDay).toISOString(),
          dateEnd: dayjs().year(year).month(month).endOf('month').toISOString(),
          roleSelect,
          project_id: projectSelect?._id,
        }),
      );
      setCountDay(dayjs(`${year}-${month + 1}`).daysInMonth() - 15);
      setStartDay(16);
    }
  };

  const clearFilters = () => {
    setEmSelect(undefined);
    setProjectSelect(undefined);
    setRoleSelect(undefined);
  };

  const handleMenuOpen = (event) => {
    setMenuAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setMenuAnchorEl(null);
  };

  const handlePreviousMonth = () => {
    if (month === 0) {
      setMonth(11);
      setYear(year - 1);
    } else {
      setMonth(month - 1);
    }
  };

  const handleNextMonth = () => {
    if (month === 11) {
      setMonth(0);
      setYear(year + 1);
    } else {
      setMonth(month + 1);
    }
  };

  const handleChangeMonth = (event) => {
    setMonth(parseInt(event.target.value));
  };

  const handleChangeYear = (event) => {
    setYear(parseInt(event.target.value));
  };

  // Render compact header with month selection
  const renderCompactHeader = () => (
    <Box
      sx={{
        mb: 2,
        display: 'flex',
        flexWrap: 'wrap',
        alignItems: 'center',
        gap: 1,
        justifyContent: 'space-between',
      }}
    >
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        <FormControl size="small" sx={{ minWidth: 120 }}>
          <Select
            value={month}
            onChange={handleChangeMonth}
            displayEmpty
            variant="outlined"
            sx={{ height: 36 }}
          >
            {monthNames.map((name, index) => (
              <MenuItem key={index} value={index}>
                {name}
              </MenuItem>
            ))}
          </Select>
        </FormControl>

        <FormControl size="small" sx={{ minWidth: 80 }}>
          <Select
            value={year}
            onChange={handleChangeYear}
            displayEmpty
            variant="outlined"
            sx={{ height: 36 }}
          >
            {Array.from(
              { length: 10 },
              (_, i) => new Date().getFullYear() - 4 + i,
            ).map((yearOption) => (
              <MenuItem key={yearOption} value={yearOption}>
                {yearOption}
              </MenuItem>
            ))}
          </Select>
        </FormControl>

        <ToggleButtonGroup
          value={selectedOption}
          exclusive
          onChange={(e, value) =>
            value && handleValueChange({ target: { value } })
          }
          size="small"
        >
          <ToggleButton value="Month" sx={{ py: 0.5, px: 1 }}>
            ทั้งเดือน
          </ToggleButton>
          <ToggleButton value="15" sx={{ py: 0.5, px: 1 }}>
            1-15
          </ToggleButton>
          <ToggleButton value="31" sx={{ py: 0.5, px: 1 }}>
            16-{daysInMonth}
          </ToggleButton>
        </ToggleButtonGroup>
      </Box>

      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        {/* Active filters badge */}
        {(emSelect ||
          projectSelect ||
          roleSelect ||
          selectedOption !== 'Month') && (
          <Chip
            icon={<FilterAltIcon fontSize="small" />}
            label={`ตัวกรอง ${
              [emSelect, projectSelect, roleSelect].filter(Boolean).length +
              (selectedOption !== 'Month' ? 1 : 0)
            }`}
            size="small"
            variant="outlined"
            onClick={() => setShowFilters(!showFilters)}
            deleteIcon={
              showFilters ? (
                <KeyboardArrowLeftIcon />
              ) : (
                <KeyboardArrowRightIcon />
              )
            }
            onDelete={() => setShowFilters(!showFilters)}
          />
        )}

        <Button
          variant={showFilters ? 'contained' : 'outlined'}
          size="small"
          color={showFilters ? 'primary' : 'inherit'}
          onClick={() => setShowFilters(!showFilters)}
          startIcon={<FilterAltIcon />}
          sx={{ height: 36 }}
        >
          ตัวกรอง
        </Button>
        {me?.userData?.permissions?.hr_management && (
          <Button
            variant="contained"
            size="small"
            onClick={handlePrint}
            startIcon={<PrintIcon />}
          >
            พิมพ์
          </Button>
        )}
      </Box>
    </Box>
  );

  // Render top filters panel (simplified)
  const renderTopFilters = () => (
    <Collapse in={showFilters}>
      <Paper
        elevation={0}
        sx={{
          mb: 2,
          p: 1.5,
          borderRadius: 1,
          border: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Grid container spacing={2}>
          <Grid item xs={12} sm={6} md={4}>
            <TextField
              select
              fullWidth
              label="พนักงาน"
              size="small"
              value={emSelect?._id || ''}
              onChange={(e) =>
                setEmSelect(
                  e.target.value
                    ? employees?.rows?.find((em) => em._id === e.target.value)
                    : undefined,
                )
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <PersonIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            >
              <MenuItem value="">ทั้งหมด</MenuItem>
              {employees?.rows?.map((employee) => (
                <MenuItem key={employee._id} value={employee._id}>
                  {employee.firstname} {employee.lastname}
                </MenuItem>
              ))}
            </TextField>
          </Grid>

          <Grid item xs={12} sm={6} md={4}>
            <TextField
              select
              fullWidth
              label="ตำแหน่ง"
              size="small"
              value={roleSelect?._id || ''}
              onChange={(e) =>
                setRoleSelect(
                  e.target.value
                    ? roletype?.rows?.find(
                        (role) => role._id === e.target.value,
                      )
                    : undefined,
                )
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <WorkIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            >
              <MenuItem value="">ทั้งหมด</MenuItem>
              {roletype?.rows?.map((role) => (
                <MenuItem key={role._id} value={role._id}>
                  {role.name}
                </MenuItem>
              ))}
            </TextField>
          </Grid>

          <Grid item xs={12} md={4}>
            <TextField
              select
              fullWidth
              label="โครงการ"
              size="small"
              value={projectSelect?._id || ''}
              onChange={(e) =>
                setProjectSelect(
                  e.target.value
                    ? project?.rows?.find((p) => p._id === e.target.value)
                    : undefined,
                )
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <BusinessIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            >
              <MenuItem value="">ทั้งหมด</MenuItem>
              {project?.rows?.map((proj) => (
                <MenuItem key={proj._id} value={proj._id}>
                  {proj.name}
                </MenuItem>
              ))}
            </TextField>
          </Grid>
        </Grid>

        {(emSelect || projectSelect || roleSelect) && (
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 2 }}>
            <Button
              size="small"
              startIcon={<FilterAltOffIcon />}
              onClick={clearFilters}
            >
              ล้างตัวกรอง
            </Button>
          </Box>
        )}
      </Paper>
    </Collapse>
  );

  // Render report content with minimal styling
  const renderReportContent = () => (
    <Paper
      elevation={0}
      sx={{
        borderRadius: 1,
        overflow: 'hidden',
        border: '1px solid',
        borderColor: 'divider',
      }}
    >
      <Box
        sx={{
          p: 1,
          bgcolor: alpha(theme.palette.background.default, 0.5),
          borderBottom: '1px solid',
          borderColor: 'divider',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <Typography variant="subtitle1" fontWeight={500}>
          รายงานข้อมูล
          {selectedOption === 'Month'
            ? 'ทั้งเดือน'
            : selectedOption === '15'
            ? ' 1-15'
            : ` 16-${daysInMonth}`}{' '}
          {monthNames[month]} {year}
        </Typography>

        <Box>
          <IconButton size="small" onClick={handlePreviousMonth}>
            <KeyboardArrowLeftIcon fontSize="small" />
          </IconButton>
          <IconButton
            size="small"
            onClick={() => {
              setMonth(dayjs().month());
              setYear(dayjs().year());
            }}
          >
            <TodayIcon fontSize="small" />
          </IconButton>
          <IconButton size="small" onClick={handleNextMonth}>
            <KeyboardArrowRightIcon fontSize="small" />
          </IconButton>
        </Box>
      </Box>

      <Fade in={true} timeout={500}>
        <Box>
          <Monthlyreport
            timestamp={timestamp}
            month={month}
            setMonth={setMonth}
            year={year}
            setYear={setYear}
            daysInMonth={daysInMonth}
            days={days}
            dateStart={dateStart}
            handleValueChange={handleValueChange}
            selectedOption={selectedOption}
            permission={me?.userData?.permissions}
          />
        </Box>
      </Fade>
    </Paper>
  );

  return (
    <div>
      <ViewTitle title={title} subtitle={subtitle} />

      {renderCompactHeader()}
      {renderTopFilters()}
      {renderReportContent()}
    </div>
  );
}
