import pdfMake from 'addthaifont-pdfmake';
import 'addthaifont-pdfmake/build/vfs_fonts';
import buddhistEra from 'dayjs/plugin/buddhistEra';
import LocalizedFormat from 'dayjs/plugin/localizedFormat';
import dayjs, { Dayjs } from 'dayjs';

import _ from 'lodash';

pdfMake.fonts = {
  Sarabun: {
    normal: 'Sarabun-Light.ttf',
    bold: 'Sarabun-Regular.ttf',
    italics: 'Sarabun-LightItalic.ttf',
    bolditalics: 'Sarabun-Italic.ttf',
  },
};

dayjs.locale('th');
dayjs.extend(buddhistEra);
dayjs.extend(LocalizedFormat);

// Format number to currency
const formatCurrency = (number) => {
  return number?.toFixed(2)?.replace(/\d(?=(\d{3})+\.)/g, '$&,') || '0.00';
};

// Generate table body rows
const genBody = (rows) => {
  const salaryList = _.map(rows, (row, index) => {
    // Calculate total income
    const totalIncome =
      (row?.revenue?.salary || 0) +
      (row?.revenue?.allowance || 0) +
      (row?.revenue?.bonus || 0) +
      (row?.revenue?.ot || 0);

    return [
      { text: index + 1, alignment: 'center' },
      {
        text: [
          { text: row?.employeeData?.firstname || '' },
          { text: '\t' },
          { text: row?.employeeData?.lastname || '' },
        ],
      },
      { text: formatCurrency(row?.revenue?.salary || 0), alignment: 'right' },
      {
        text: formatCurrency(row?.revenue?.allowance || 0),
        alignment: 'right',
      },
      { text: formatCurrency(row?.revenue?.bonus || 0), alignment: 'right' },
      { text: formatCurrency(row?.revenue?.overtime || 0), alignment: 'right' },

      { text: formatCurrency(row?.expenses?.tax || 0), alignment: 'right' },
      { text: formatCurrency(row?.expenses?.sso || 0), alignment: 'right' },
      {
        text: formatCurrency(row?.expenses?.timestamp || 0),
        alignment: 'right',
      },
      { text: formatCurrency(row?.expenses?.other || 0), alignment: 'right' },

      { text: formatCurrency(row?.total || 0), alignment: 'right', bold: true },
    ];
  });

  return salaryList;
};

// Generate summary row for the table footer
const genSummaryRow = (data) => {
  // Calculate totals
  let totalSalary = 0;
  let totalAllowance = 0;
  let totalBonus = 0;
  let totalOT = 0;
  let totalIncome = 0;
  let totalTax = 0;
  let totalSocialSecurity = 0;
  let totalProvidentFund = 0;
  let totalAdvance = 0;
  let totalDeduction = 0;
  let totalNetSalary = 0;

  data.forEach((row) => {
    totalSalary += row?.revenue?.salary || 0;
    totalAllowance += row?.revenue?.allowance || 0;
    totalBonus += row?.revenue?.bonus || 0;
    totalOT += row?.revenue?.ot || 0;
    totalIncome +=
      (row?.revenue?.salary || 0) +
      (row?.revenue?.allowance || 0) +
      (row?.revenue?.bonus || 0) +
      (row?.revenue?.ot || 0);
    totalTax += row?.tax || 0;
    totalSocialSecurity += row?.socialSecurity || 0;
    totalProvidentFund += row?.providentFund || 0;
    totalAdvance += row?.advance || 0;
    totalDeduction += row?.totalDeduction || 0;
    totalNetSalary += row?.total || 0;
  });

  return [
    { text: '', border: [true, true, true, true] },
    {
      text: 'รวมทั้งสิ้น',
      alignment: 'center',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalSalary),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalAllowance),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalBonus),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalOT),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalIncome),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
      fillColor: '#f2f2f2',
    },
    {
      text: formatCurrency(totalTax),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalSocialSecurity),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalProvidentFund),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalAdvance),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
    },
    {
      text: formatCurrency(totalDeduction),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
      fillColor: '#f2f2f2',
    },
    {
      text: formatCurrency(totalNetSalary),
      alignment: 'right',
      bold: true,
      border: [true, true, true, true],
      fillColor: '#d2d4d2',
    },
  ];
};

const payrollReport = async (data) => {
  // Format month and year for the header
  const monthYear = dayjs(data?.dateStart).format('MMMM BBBB');

  const genItemBody = genBody(data?.salaryData || []);
  const summaryRow = genSummaryRow(data?.salaryData || []);

  const documentRef = {
    pageSize: 'A4',
    pageOrientation: 'landscape',
    pageMargins: [10, 80, 10, 60],
    defaultStyle: {
      font: 'Sarabun',
      fontSize: 10,
    },
    info: {
      title: 'รายงานการจ่ายเงินเดือนประจำเดือน',
      subject: monthYear,
      author: 'MNS System',
    },
    header: [
      {
        margin: [0, 12],
        table: {
          alignment: '',
          headerRows: 1,
          widths: ['100%'],
          body: [
            [
              {
                text: [
                  {
                    text: 'รายงานการจ่ายเงินเดือนประจำเดือน ',
                    style: 'headerPage',
                  },
                  { text: monthYear, style: 'headerPage' },
                ],
                border: [false, false, false, false],
              },
            ],
          ],
        },
      },
    ],
    content: [
      {
        text:
          'ช่วงวันที่ ' +
          `${dayjs(data?.dateStart).format('DD/MM/BBBB')} - ${dayjs(
            data?.dateEnd,
          ).format('DD/MM/BBBB')}`,
        margin: [0, 0, 0, 4],
      },
      {
        text:
          'ประเภท ' +
          `${
            data?.role_type === 'DAILY' ? 'พนักงานรายวัน' : 'พนักงานรายเดือน'
          }`,
        margin: [0, 0, 0, 4],
      },
      {
        table: {
          alignment: '',
          headerRows: 1,
          widths: [
            '6%', // ลำดับ
            '22%', // ชื่อ-นามสกุล
            '7%', // เงินเดือน
            '7%', // เบี้ยเลี้ยง
            '7%', // โบนัส
            '7%', // ค่าล่วงเวลา
            '7%', // ภาษี
            '9%', // ปกส
            '9%', // นายจ้างสมทบ
            '7%', // เงินล่วงหน้า
            '12%', // เงินสุทธิ
          ],
          body: [
            [
              {
                text: 'ลำดับ',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'ชื่อ-นามสกุล',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },

              {
                text: 'เงินเดือน',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'เบี้ยเลี้ยง',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'โบนัส',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'ค่าล่วงเวลา',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },

              {
                text: 'ภาษี',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'ประกันสังคม',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'นายจ้างสมทบ',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
              {
                text: 'อื่นๆ',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },

              {
                text: 'สุทธิ',
                fillColor: '#d2d4d2',
                alignment: 'center',
                border: [true, true, true, true],
              },
            ],
            ...genItemBody,
            // summaryRow,
          ],
        },
      },
    ],

    footer: function (currentPage, pageCount) {
      return {
        columns: [
          {
            text: 'เอกสารใช้ภายในบริษัทเท่านั้น',
            alignment: 'left',
            fontSize: 8,
            margin: [10, 0, 0, 0],
          },
          {
            text: 'หน้า ' + currentPage.toString() + ' จาก ' + pageCount,
            alignment: 'right',
            fontSize: 8,
            margin: [0, 0, 10, 0],
          },
        ],
      };
    },

    styles: {
      headerPage: {
        fontSize: 16,
        bold: true,
        alignment: 'center',
      },
    },
  };

  pdfMake.createPdf(documentRef).open();
};

export default payrollReport;
